# Prompt: Build a Python Flask file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

import os
import mimetypes
from datetime import datetime
from flask import Flask, request, jsonify, send_file, abort

app = Flask(__name__)

USER_ROOTS = {
    "demo": os.path.abspath(os.path.join(os.getcwd(), "uploads", "demo")),
}

for root in USER_ROOTS.values():
    os.makedirs(root, exist_ok=True)


def get_user_root(user_id: str) -> str:
    root = USER_ROOTS.get(user_id)
    if not root:
        abort(404, description="User not found")
    return root


def resolve_user_path(user_root: str, relative_path: str) -> str:
    relative_path = relative_path or ""
    normalized_relative = os.path.normpath(relative_path)

    if normalized_relative in (".", os.sep):
        normalized_relative = ""

    full_path = os.path.normpath(os.path.join(user_root, normalized_relative))
    user_root_abs = os.path.abspath(user_root)
    full_path_abs = os.path.abspath(full_path)

    try:
        common = os.path.commonpath([user_root_abs, full_path_abs])
    except ValueError:
        abort(400, description="Invalid path")

    if common != user_root_abs:
        abort(403, description="Path escapes user root")

    return full_path_abs


def stat_to_info(path: str) -> dict:
    st = os.stat(path)
    return {
        "name": os.path.basename(path),
        "path": path,
        "is_dir": os.path.isdir(path),
        "is_file": os.path.isfile(path),
        "size": st.st_size,
        "modified_at": datetime.fromtimestamp(st.st_mtime).isoformat(),
        "created_at": datetime.fromtimestamp(st.st_ctime).isoformat(),
        "mime_type": None if os.path.isdir(path) else mimetypes.guess_type(path)[0],
    }


@app.route("/api/files/list", methods=["GET"])
def list_directory():
    user_id = request.args.get("user_id", "").strip()
    relative_path = request.args.get("path", "")

    user_root = get_user_root(user_id)
    target_path = resolve_user_path(user_root, relative_path)

    if not os.path.exists(target_path):
        abort(404, description="Path not found")
    if not os.path.isdir(target_path):
        abort(400, description="Path is not a directory")

    items = []
    for name in sorted(os.listdir(target_path)):
        child_path = os.path.join(target_path, name)
        st = os.stat(child_path)
        items.append({
            "name": name,
            "relative_path": os.path.relpath(child_path, user_root).replace("\\", "/") if child_path != user_root else "",
            "is_dir": os.path.isdir(child_path),
            "is_file": os.path.isfile(child_path),
            "size": st.st_size,
            "modified_at": datetime.fromtimestamp(st.st_mtime).isoformat(),
        })

    return jsonify({
        "user_id": user_id,
        "path": "" if os.path.abspath(target_path) == os.path.abspath(user_root) else os.path.relpath(target_path, user_root).replace("\\", "/"),
        "items": items,
    })


@app.route("/api/files/download", methods=["GET"])
def download_file():
    user_id = request.args.get("user_id", "").strip()
    relative_path = request.args.get("path", "")

    user_root = get_user_root(user_id)
    target_path = resolve_user_path(user_root, relative_path)

    if not os.path.exists(target_path):
        abort(404, description="File not found")
    if not os.path.isfile(target_path):
        abort(400, description="Path is not a file")

    return send_file(target_path, as_attachment=True, download_name=os.path.basename(target_path))


@app.route("/api/files/info", methods=["GET"])
def file_info():
    user_id = request.args.get("user_id", "").strip()
    relative_path = request.args.get("path", "")

    user_root = get_user_root(user_id)
    target_path = resolve_user_path(user_root, relative_path)

    if not os.path.exists(target_path):
        abort(404, description="Path not found")

    info = stat_to_info(target_path)
    info["relative_path"] = "" if os.path.abspath(target_path) == os.path.abspath(user_root) else os.path.relpath(target_path, user_root).replace("\\", "/")
    return jsonify(info)


@app.errorhandler(400)
@app.errorhandler(403)
@app.errorhandler(404)
def handle_error(err):
    return jsonify({"error": err.description}), err.code


if __name__ == "__main__":
    app.run(debug=True)